import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { Search, MapPin, Calendar, Clock, User, Trash2 } from 'lucide-react';

const AdminPanel = () => {
  const [users, setUsers] = useState([]);
  const [trajets, setTrajets] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('users');

  const fetchData = async () => {
    setLoading(true);
    try {
      const [usersRes, trajetsRes] = await Promise.all([
        api.get('/admin/users'),
        api.get('/trajets')
      ]);
      setUsers(usersRes.data);
      setTrajets(trajetsRes.data);
    } catch (error) {
      console.error("Erreur de récupération des données admin", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleDeleteUser = async (id) => {
    if (window.confirm('Voulez-vous vraiment supprimer cet utilisateur ?')) {
      try {
        await api.delete(`/admin/users/${id}`);
        setUsers(users.filter(u => u.id !== id));
      } catch (error) {
        alert(error.response?.data || "Erreur lors de la suppression");
      }
    }
  };

  const handleDeleteTrajet = async (id) => {
    if (window.confirm('Voulez-vous vraiment supprimer ce trajet ?')) {
      try {
        await api.delete(`/admin/trajets/${id}`);
        setTrajets(trajets.filter(t => t.id !== id));
      } catch (error) {
        alert("Erreur lors de la suppression");
      }
    }
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Chargement des données administrateur...</div>;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold text-slate-900">Panel d'Administration</h1>
          <p className="text-slate-500 mt-1">Gérez les utilisateurs et les annonces de la plateforme.</p>
        </div>

        <div className="flex bg-slate-100 p-1 rounded-lg">
          <button
            onClick={() => setActiveTab('users')}
            className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${activeTab === 'users' ? 'bg-white text-primary-600 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
          >
            Utilisateurs ({users.length})
          </button>
          <button
            onClick={() => setActiveTab('trajets')}
            className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${activeTab === 'trajets' ? 'bg-white text-primary-600 shadow-sm' : 'text-slate-600 hover:text-slate-900'}`}
          >
            Trajets ({trajets.length})
          </button>
        </div>
      </div>

      {activeTab === 'users' && (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="min-w-full divide-y divide-slate-200">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Utilisateur</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Contact</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Rôle</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-slate-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-200">
              {users.map(user => (
                <tr key={user.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="flex items-center">
                      <div className="flex-shrink-0 h-10 w-10 rounded-full bg-primary-100 flex items-center justify-center text-primary-700 font-bold">
                        {user.nom.charAt(0).toUpperCase()}
                      </div>
                      <div className="ml-4">
                        <div className="text-sm font-medium text-slate-900">{user.nom}</div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="text-sm text-slate-900">{user.email}</div>
                    <div className="text-sm text-slate-500">{user.telephone}</div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full 
                      ${user.role === 'ADMIN' ? 'bg-purple-100 text-purple-800' : 
                        user.role === 'CONDUCTEUR' ? 'bg-blue-100 text-blue-800' : 'bg-green-100 text-green-800'}`}>
                      {user.role}
                    </span>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                    {user.role !== 'ADMIN' && (
                      <button onClick={() => handleDeleteUser(user.id)} className="text-red-600 hover:text-red-900 bg-red-50 p-2 rounded-lg transition-colors">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {activeTab === 'trajets' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {trajets.map(trajet => (
            <div key={trajet.id} className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col h-full">
              <div className="flex justify-between items-start mb-4">
                <div className="flex items-center gap-2">
                  <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-600 font-semibold text-sm">
                    {trajet.conducteur?.nom?.charAt(0) || '?'}
                  </div>
                  <span className="text-sm font-medium text-slate-700">{trajet.conducteur?.nom || 'Inconnu'}</span>
                </div>
                <span className="text-lg font-bold text-primary-600">{trajet.prix} MAD</span>
              </div>

              <div className="flex flex-col gap-3 flex-grow">
                <div className="flex items-center gap-3 text-slate-700">
                  <MapPin className="w-5 h-5 text-slate-400" />
                  <span className="font-medium">{trajet.villeDepart} <span className="text-slate-400 mx-1">→</span> {trajet.villeArrivee}</span>
                </div>
                <div className="flex items-center gap-3 text-slate-600 text-sm">
                  <Calendar className="w-4 h-4 text-slate-400" />
                  <span>{trajet.dateDepart}</span>
                  <Clock className="w-4 h-4 text-slate-400 ml-2" />
                  <span>{trajet.heureDepart}</span>
                </div>
                <div className="flex items-center gap-3 text-slate-600 text-sm mt-auto pt-4 border-t border-slate-100">
                  <User className="w-4 h-4 text-slate-400" />
                  <span>{trajet.placesDisponibles} place(s) disponible(s)</span>
                </div>
              </div>

              <button 
                onClick={() => handleDeleteTrajet(trajet.id)}
                className="mt-4 w-full flex items-center justify-center gap-2 py-2 px-4 border border-red-200 text-red-600 rounded-lg hover:bg-red-50 transition-colors text-sm font-medium"
              >
                <Trash2 className="w-4 h-4" />
                Supprimer l'annonce
              </button>
            </div>
          ))}

          {trajets.length === 0 && (
            <div className="col-span-full py-12 text-center text-slate-500 bg-white rounded-xl border border-slate-200 border-dashed">
              Aucun trajet publié pour le moment.
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default AdminPanel;

import React, { useState, useEffect } from 'react';
import api from '../services/api';
import { Search, MapPin, Calendar, ArrowRight } from 'lucide-react';

const Home = () => {
  const [searchParams, setSearchParams] = useState({
    depart: '',
    arrivee: '',
    date: ''
  });
  const [trajets, setTrajets] = useState([]);
  const [hasSearched, setHasSearched] = useState(false);
  const [loading, setLoading] = useState(false);
  const [allTrajets, setAllTrajets] = useState([]);

  useEffect(() => {
    // Charger quelques trajets récents par défaut
    const fetchRecent = async () => {
      try {
        const res = await api.get('/trajets');
        setAllTrajets(res.data.slice(0, 6)); // Prendre les 6 premiers
      } catch (e) {
        console.error("Erreur de récupération des trajets récents");
      }
    };
    fetchRecent();
  }, []);

  const handleSearch = async (e) => {
    e.preventDefault();
    if (!searchParams.depart || !searchParams.arrivee || !searchParams.date) return;

    setLoading(true);
    setHasSearched(true);
    try {
      const res = await api.get(`/trajets/search?depart=${searchParams.depart}&arrivee=${searchParams.arrivee}&date=${searchParams.date}`);
      setTrajets(res.data);
    } catch (error) {
      console.error("Erreur de recherche", error);
    } finally {
      setLoading(false);
    }
  };

  const handleReservation = async (trajetId) => {
    try {
      await api.post(`/reservations/trajet/${trajetId}`);
      alert('Réservation effectuée avec succès !');
      // Mettre à jour la disponibilité locale
      if (hasSearched) {
        setTrajets(trajets.map(t => t.id === trajetId ? { ...t, placesDisponibles: t.placesDisponibles - 1 } : t));
      } else {
        setAllTrajets(allTrajets.map(t => t.id === trajetId ? { ...t, placesDisponibles: t.placesDisponibles - 1 } : t));
      }
    } catch (error) {
      if (error.response?.status === 401) {
        alert("Vous devez être connecté pour réserver.");
        window.location.href = '/login';
      } else {
        alert(error.response?.data || "Erreur lors de la réservation");
      }
    }
  };

  const TrajetCard = ({ trajet }) => (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-5 hover:shadow-md transition-shadow relative overflow-hidden group">
      <div className="absolute top-0 right-0 bg-primary-50 text-primary-700 px-3 py-1 rounded-bl-lg font-bold">
        {trajet.prix} MAD
      </div>

      <div className="flex flex-col h-full mt-2">
        <div className="flex justify-between items-center mb-6">
          <div className="flex flex-col gap-1 w-full relative">
            <div className="flex items-center gap-3 relative z-10">
              <span className="font-bold text-slate-800 text-lg">{trajet.heureDepart}</span>
              <span className="font-medium text-slate-700 flex-1">{trajet.villeDepart}</span>
            </div>

            <div className="absolute left-10 top-6 bottom-6 w-0.5 bg-slate-200 z-0 hidden md:block"></div>

            <div className="flex items-center gap-3 relative z-10 mt-4">
              <span className="font-bold text-slate-500 text-sm">Fin</span>
              <span className="font-medium text-slate-700 flex-1">{trajet.villeArrivee}</span>
            </div>
          </div>
        </div>

        <div className="mt-auto pt-4 border-t border-slate-100 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-slate-600 font-semibold text-sm">
              {trajet.conducteur?.nom?.charAt(0) || '?'}
            </div>
            <div>
              <p className="text-sm font-medium text-slate-700">{trajet.conducteur?.nom}</p>
              <p className="text-xs text-slate-500">{trajet.placesDisponibles} places restantes</p>
            </div>
          </div>

          <button 
            onClick={() => handleReservation(trajet.id)}
            disabled={trajet.placesDisponibles <= 0}
            className="btn-primary py-1.5 px-4 text-sm"
          >
            {trajet.placesDisponibles > 0 ? 'Réserver' : 'Complet'}
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-[calc(100vh-64px)] bg-slate-50">
      {/* Hero Section */}
      <div className="bg-primary-600 pb-24 pt-16 px-4">
        <div className="max-w-4xl mx-auto text-center text-white">
          <h1 className="text-4xl font-extrabold tracking-tight sm:text-5xl lg:text-6xl mb-6">
            Vos trajets, <span className="text-primary-200">moins chers</span>.
          </h1>
          <p className="text-xl max-w-2xl mx-auto opacity-90 mb-10">
            Trouvez des covoiturages partout au Maroc, réservez facilement et voyagez en toute sérénité.
          </p>
        </div>
      </div>

      {/* Search Bar (Overlapping Hero) */}
      <div className="max-w-5xl mx-auto px-4 -mt-16 relative z-10 mb-16">
        <form onSubmit={handleSearch} className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-100 p-3 sm:p-2 flex flex-col md:flex-row items-center gap-2">

          <div className="flex-1 relative w-full md:w-auto">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
              <MapPin className="h-5 w-5" />
            </div>
            <input 
              type="text" 
              required 
              className="w-full bg-slate-50 border-0 rounded-xl focus:ring-2 focus:ring-primary-500 pl-10 py-3 text-slate-900 placeholder:text-slate-500 font-medium" 
              placeholder="Départ" 
              value={searchParams.depart} 
              onChange={e => setSearchParams({...searchParams, depart: e.target.value})} 
            />
          </div>

          <div className="h-px w-full md:w-px md:h-10 bg-slate-200"></div>

          <div className="flex-1 relative w-full md:w-auto">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
              <MapPin className="h-5 w-5" />
            </div>
            <input 
              type="text" 
              required 
              className="w-full bg-slate-50 border-0 rounded-xl focus:ring-2 focus:ring-primary-500 pl-10 py-3 text-slate-900 placeholder:text-slate-500 font-medium" 
              placeholder="Destination" 
              value={searchParams.arrivee} 
              onChange={e => setSearchParams({...searchParams, arrivee: e.target.value})} 
            />
          </div>

          <div className="h-px w-full md:w-px md:h-10 bg-slate-200"></div>

          <div className="flex-1 relative w-full md:w-auto">
            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
              <Calendar className="h-5 w-5" />
            </div>
            <input 
              type="date" 
              required 
              className="w-full bg-slate-50 border-0 rounded-xl focus:ring-2 focus:ring-primary-500 pl-10 py-3 text-slate-900 placeholder:text-slate-500 font-medium" 
              value={searchParams.date} 
              onChange={e => setSearchParams({...searchParams, date: e.target.value})} 
            />
          </div>

          <button type="submit" className="w-full md:w-auto btn-primary py-3 px-8 text-lg rounded-xl h-full flex items-center justify-center gap-2">
            <Search className="w-5 h-5" /> Rechercher
          </button>
        </form>
      </div>

      {/* Results Section */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pb-16">

        {loading && <div className="text-center text-slate-500 py-12">Recherche en cours...</div>}

        {!loading && hasSearched && (
          <div>
            <h2 className="text-2xl font-bold text-slate-900 mb-6 flex items-center gap-2">
              Résultats de recherche
              <span className="text-sm font-normal text-slate-500 bg-slate-100 px-3 py-1 rounded-full">{trajets.length} trajet(s) trouvé(s)</span>
            </h2>

            {trajets.length > 0 ? (
               <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                 {trajets.map(t => <TrajetCard key={t.id} trajet={t} />)}
               </div>
            ) : (
              <div className="bg-white text-center py-16 rounded-2xl border border-slate-200 shadow-sm">
                <Search className="w-12 h-12 text-slate-300 mx-auto mb-4" />
                <h3 className="text-lg font-medium text-slate-900 mb-2">Aucun trajet trouvé</h3>
                <p className="text-slate-500 max-w-md mx-auto">Il n'y a pas de trajets correspondant à vos critères pour cette date. Essayez une date différente ou élargissez vos critères de recherche.</p>
              </div>
            )}
          </div>
        )}

        {!loading && !hasSearched && allTrajets.length > 0 && (
          <div>
            <div className="flex justify-between items-end mb-6">
              <h2 className="text-2xl font-bold text-slate-900">Annonces récentes</h2>
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
               {allTrajets.map(t => <TrajetCard key={t.id} trajet={t} />)}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Home;

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import api from '../services/api';
import { Car, Mail, Lock } from 'lucide-react';

const Login = () => {
  const [formData, setFormData] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const response = await api.post('/auth/login', formData);
      localStorage.setItem('token', response.data.token);
      localStorage.setItem('user', JSON.stringify({
        role: response.data.role,
        nom: response.data.nom
      }));

      if (response.data.role === 'ADMIN') {
        navigate('/admin');
      } else {
        navigate('/');
      }
    } catch (err) {
      setError('Email ou mot de passe incorrect');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col justify-center py-12 sm:px-6 lg:px-8">
      <div className="sm:mx-auto sm:w-full sm:max-w-md">
        <div className="flex justify-center text-primary-600">
          <Car className="w-12 h-12" />
        </div>
        <h2 className="mt-6 text-center text-3xl font-extrabold text-slate-900">
          Bon retour parmis nous !
        </h2>
        <p className="mt-2 text-center text-sm text-slate-600">
          Ou <Link to="/register" className="font-medium text-primary-600 hover:text-primary-500">créez un nouveau compte</Link>
        </p>
      </div>

      <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md">
        <div className="bg-white py-8 px-4 shadow-xl shadow-slate-200/50 sm:rounded-xl sm:px-10 border border-slate-100">
          <form className="space-y-6" onSubmit={handleSubmit}>
            {error && (
              <div className="bg-red-50 text-red-700 p-3 rounded-lg text-sm mb-4">
                {error}
              </div>
            )}

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">
                Adresse Email
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                  <Mail className="h-5 w-5" />
                </div>
                <input
                  type="email"
                  required
                  className="input-field pl-10"
                  placeholder="vous@exemple.com"
                  value={formData.email}
                  onChange={(e) => setFormData({...formData, email: e.target.value})}
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">
                Mot de passe
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                  <Lock className="h-5 w-5" />
                </div>
                <input
                  type="password"
                  required
                  className="input-field pl-10"
                  placeholder="••••••••"
                  value={formData.password}
                  onChange={(e) => setFormData({...formData, password: e.target.value})}
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full btn-primary flex justify-center py-2.5"
            >
              {loading ? 'Connexion...' : 'Se connecter'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../services/api';
import { MapPin, Calendar, Clock, DollarSign, Users } from 'lucide-react';

const ProposerTrajet = () => {
  const [formData, setFormData] = useState({
    villeDepart: '',
    villeArrivee: '',
    dateDepart: '',
    heureDepart: '',
    placesDisponibles: 3,
    prix: 50
  });
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await api.post('/trajets', formData);
      alert('Votre trajet a été publié avec succès !');
      navigate('/');
    } catch (error) {
      alert("Erreur lors de la publication du trajet.");
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <div className="max-w-3xl mx-auto px-4 py-12 sm:px-6 lg:px-8">
      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">
        <div className="bg-primary-600 px-8 py-6 text-white text-center">
          <h1 className="text-2xl font-bold">Proposer un nouveau trajet</h1>
          <p className="opacity-90 mt-1">Partagez vos frais de route en bonne compagnie</p>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Ville de départ</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                  <MapPin className="h-5 w-5" />
                </div>
                <input type="text" name="villeDepart" required className="input-field pl-10" placeholder="Ex: Casablanca" value={formData.villeDepart} onChange={handleChange} />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Ville d'arrivée</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                  <MapPin className="h-5 w-5" />
                </div>
                <input type="text" name="villeArrivee" required className="input-field pl-10" placeholder="Ex: Rabat" value={formData.villeArrivee} onChange={handleChange} />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Date</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                  <Calendar className="h-5 w-5" />
                </div>
                <input type="date" name="dateDepart" required className="input-field pl-10" value={formData.dateDepart} onChange={handleChange} />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Heure de départ</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                  <Clock className="h-5 w-5" />
                </div>
                <input type="time" name="heureDepart" required className="input-field pl-10" value={formData.heureDepart} onChange={handleChange} />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Places disponibles</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                  <Users className="h-5 w-5" />
                </div>
                <input type="number" name="placesDisponibles" min="1" max="8" required className="input-field pl-10" value={formData.placesDisponibles} onChange={handleChange} />
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Prix par passager (MAD)</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
                  <DollarSign className="h-5 w-5" />
                </div>
                <input type="number" name="prix" min="0" required className="input-field pl-10" value={formData.prix} onChange={handleChange} />
              </div>
            </div>
          </div>

          <div className="pt-4 border-t border-slate-100 mt-8">
            <button type="submit" disabled={loading} className="w-full btn-primary py-3 text-lg">
              {loading ? 'Publication en cours...' : 'Publier le trajet'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default ProposerTrajet;
